// ─── NAV SCROLL ───
const navbar = document.getElementById("navbar");
window.addEventListener("scroll", () =>
  navbar.classList.toggle("scrolled", window.scrollY > 60),
);

// ─── MOBILE NAV ───
function toggleMobileNav() {
  document.getElementById("mobileNav").classList.toggle("open");
}

// ─── SMOOTH SCROLL ───
document.querySelectorAll('a[href^="#"]').forEach((a) => {
  a.addEventListener("click", (e) => {
    e.preventDefault();
    const t = document.querySelector(a.getAttribute("href"));
    if (t) t.scrollIntoView({ behavior: "smooth" });
    document.getElementById("mobileNav").classList.remove("open");
  });
});

// ─── INTERSECTION OBSERVER ───
const obs = new IntersectionObserver(
  (entries) => {
    entries.forEach((e) => {
      if (e.isIntersecting) e.target.classList.add("visible");
    });
  },
  { threshold: 0.08, rootMargin: "0px 0px -40px 0px" },
);
document.querySelectorAll(".fade-up").forEach((el) => obs.observe(el));

// ─── STAGGER DISH CARDS ───
document
  .querySelectorAll(".dish-card")
  .forEach((c, i) => (c.style.transitionDelay = `${i * 0.1}s`));

(function () {
  var logo =
    "data:image/jpeg;base64,";
  var img_alfaham_plate =
    "data:image/jpeg;base64,";
  var img_mandi_no1 =
    "data:image/jpeg;base64,";
  var img_mandi_delivery =
    "data:image/jpeg;base64,";
  var img_alfham_varieties =
    "data:image/jpeg;base64,";
  var img_mandi_home =
    "data:image/jpeg;base64,";
  var img_mandi_eid =
    "data:image/jpeg;base64,";
  var img_iftar1 =
    "data:image/jpeg;base64,";
  var img_iftar2 =
    "data:image/jpeg;base64,";
  var img_iftar3 =
    "data:image/jpeg;base64,";
  var img_iftar4 =
    "data:image/jpeg;base64,";
  var img_iftar5 =
    "data:image/jpeg;base64,";
  var img_iftar6 =
    "data:image/jpeg;base64,";
  var img_iftar7 =
    "data:image/jpeg;base64,";
  var img_iftar8 =
    "data:image/jpeg;base64,";

  function applyImages() {
    // Logo (all instances)
    document.querySelectorAll(".logo-img").forEach((el) => {
      el.src = logo;
    });
    document.querySelectorAll(".footer-logo-img").forEach((el) => {
      el.src = logo;
    });
    document.querySelectorAll(".hero-logo-img").forEach((el) => {
      el.src = logo;
    });

    // Hero BG
    var heroBg = document.getElementById("heroBg");
    if (heroBg)
      heroBg.style.backgroundImage = "url(" + img_alfham_varieties + ")";

    // About section
    var aboutImg = document.getElementById("about-main-img");
    if (aboutImg) aboutImg.src = img_mandi_no1;

    // Dish cards (4 dishes)
    var dishImgs = document.querySelectorAll(".dish-real-img");
    var dishSrcs = [
      img_alfaham_plate,
      img_mandi_home,
      img_mandi_eid,
      img_mandi_delivery,
    ];
    dishImgs.forEach(function (el, i) {
      if (dishSrcs[i]) el.src = dishSrcs[i];
    });

    // Iftar cards (8 total across 2 grids)
    var iftarImgs = document.querySelectorAll(".iftar-real-img");
    var iftarSrcs = [
      img_iftar1,
      img_iftar2,
      img_iftar3,
      img_iftar4,
      img_iftar5,
      img_iftar6,
      img_iftar7,
      img_iftar8,
    ];
    iftarImgs.forEach(function (el, i) {
      if (iftarSrcs[i]) el.src = iftarSrcs[i];
    });

    // Dining mosaic
    var d1 = document.getElementById("dining-img1");
    var d2 = document.getElementById("dining-img2");
    var d3 = document.getElementById("dining-img3");
    if (d1) d1.src = img_mandi_no1;
    if (d2) d2.src = img_alfham_varieties;
    if (d3) d3.src = img_mandi_delivery;

    // Gallery
    var galleryImgs = document.querySelectorAll(".gallery-real-img");
    var galSrcs = [
      img_alfham_varieties,
      img_mandi_no1,
      img_alfaham_plate,
      img_mandi_eid,
      img_mandi_delivery,
      img_mandi_home,
    ];
    galleryImgs.forEach(function (el, i) {
      if (galSrcs[i]) el.src = galSrcs[i];
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", applyImages);
  } else {
    applyImages();
  }
})();
